import numpy as np
import torch
from scipy import constants

from ..common import Function, VectorFunction
from .field_term import FieldTerm

__all__ = ["ExchangeTorchField2"]


class ExchangeTorchField2(FieldTerm):
    def __init__(self):
        self._state = None

    def h(self, state):
        if self._state is None:
            self._state = state
            self._h = VectorFunction(state)

        m = state.m

        H_slicing(
            state.m.tensor, state.material.A.tensor, self._h.tensor, state.mesh.dx
        )

        # compute lumped mass
        V = state.mesh.cell_volume
        Ms = state.material.Ms.tensor
        mass = Function(state).tensor
        mass[:-1, :-1, :-1] += V / 8.0 * Ms
        mass[:-1, :-1, 1:] += V / 8.0 * Ms
        mass[:-1, 1:, :-1] += V / 8.0 * Ms
        mass[:-1, 1:, 1:] += V / 8.0 * Ms
        mass[1:, :-1, :-1] += V / 8.0 * Ms
        mass[1:, :-1, 1:] += V / 8.0 * Ms
        mass[1:, 1:, :-1] += V / 8.0 * Ms
        mass[1:, 1:, 1:] += V / 8.0 * Ms

        self._h.tensor.multiply_(-1.0 / (constants.mu_0 * mass.unsqueeze(-1)))

        return self._h


def H_slicing(m, A, h, dx):
    h[:] = 0.0
    h[:-1,:-1,:-1,0] += 0.222222222222222*A[:,:,:]*(1.0*dx[0]**2*dx[1]**2*m[:-1,:-1,:-1,0] - 1.0*dx[0]**2*dx[1]**2*m[:-1,:-1,1:,0] + 0.5*dx[0]**2*dx[1]**2*m[:-1,1:,:-1,0] - 0.5*dx[0]**2*dx[1]**2*m[:-1,1:,1:,0] + 0.5*dx[0]**2*dx[1]**2*m[1:,:-1,:-1,0] - 0.5*dx[0]**2*dx[1]**2*m[1:,:-1,1:,0] + 0.25*dx[0]**2*dx[1]**2*m[1:,1:,:-1,0] - 0.25*dx[0]**2*dx[1]**2*m[1:,1:,1:,0] + 1.0*dx[0]**2*dx[2]**2*m[:-1,:-1,:-1,0] + 0.5*dx[0]**2*dx[2]**2*m[:-1,:-1,1:,0] - 1.0*dx[0]**2*dx[2]**2*m[:-1,1:,:-1,0] - 0.5*dx[0]**2*dx[2]**2*m[:-1,1:,1:,0] + 0.5*dx[0]**2*dx[2]**2*m[1:,:-1,:-1,0] + 0.25*dx[0]**2*dx[2]**2*m[1:,:-1,1:,0] - 0.5*dx[0]**2*dx[2]**2*m[1:,1:,:-1,0] - 0.25*dx[0]**2*dx[2]**2*m[1:,1:,1:,0] + 1.0*dx[1]**2*dx[2]**2*m[:-1,:-1,:-1,0] + 0.5*dx[1]**2*dx[2]**2*m[:-1,:-1,1:,0] + 0.5*dx[1]**2*dx[2]**2*m[:-1,1:,:-1,0] + 0.25*dx[1]**2*dx[2]**2*m[:-1,1:,1:,0] - 1.0*dx[1]**2*dx[2]**2*m[1:,:-1,:-1,0] - 0.5*dx[1]**2*dx[2]**2*m[1:,:-1,1:,0] - 0.5*dx[1]**2*dx[2]**2*m[1:,1:,:-1,0] - 0.25*dx[1]**2*dx[2]**2*m[1:,1:,1:,0])/(dx[0]*dx[1]*dx[2])
    h[:-1,:-1,:-1,1] += 0.222222222222222*A[:,:,:]*(1.0*dx[0]**2*dx[1]**2*m[:-1,:-1,:-1,1] - 1.0*dx[0]**2*dx[1]**2*m[:-1,:-1,1:,1] + 0.5*dx[0]**2*dx[1]**2*m[:-1,1:,:-1,1] - 0.5*dx[0]**2*dx[1]**2*m[:-1,1:,1:,1] + 0.5*dx[0]**2*dx[1]**2*m[1:,:-1,:-1,1] - 0.5*dx[0]**2*dx[1]**2*m[1:,:-1,1:,1] + 0.25*dx[0]**2*dx[1]**2*m[1:,1:,:-1,1] - 0.25*dx[0]**2*dx[1]**2*m[1:,1:,1:,1] + 1.0*dx[0]**2*dx[2]**2*m[:-1,:-1,:-1,1] + 0.5*dx[0]**2*dx[2]**2*m[:-1,:-1,1:,1] - 1.0*dx[0]**2*dx[2]**2*m[:-1,1:,:-1,1] - 0.5*dx[0]**2*dx[2]**2*m[:-1,1:,1:,1] + 0.5*dx[0]**2*dx[2]**2*m[1:,:-1,:-1,1] + 0.25*dx[0]**2*dx[2]**2*m[1:,:-1,1:,1] - 0.5*dx[0]**2*dx[2]**2*m[1:,1:,:-1,1] - 0.25*dx[0]**2*dx[2]**2*m[1:,1:,1:,1] + 1.0*dx[1]**2*dx[2]**2*m[:-1,:-1,:-1,1] + 0.5*dx[1]**2*dx[2]**2*m[:-1,:-1,1:,1] + 0.5*dx[1]**2*dx[2]**2*m[:-1,1:,:-1,1] + 0.25*dx[1]**2*dx[2]**2*m[:-1,1:,1:,1] - 1.0*dx[1]**2*dx[2]**2*m[1:,:-1,:-1,1] - 0.5*dx[1]**2*dx[2]**2*m[1:,:-1,1:,1] - 0.5*dx[1]**2*dx[2]**2*m[1:,1:,:-1,1] - 0.25*dx[1]**2*dx[2]**2*m[1:,1:,1:,1])/(dx[0]*dx[1]*dx[2])
    h[:-1,:-1,:-1,2] += 0.222222222222222*A[:,:,:]*(1.0*dx[0]**2*dx[1]**2*m[:-1,:-1,:-1,2] - 1.0*dx[0]**2*dx[1]**2*m[:-1,:-1,1:,2] + 0.5*dx[0]**2*dx[1]**2*m[:-1,1:,:-1,2] - 0.5*dx[0]**2*dx[1]**2*m[:-1,1:,1:,2] + 0.5*dx[0]**2*dx[1]**2*m[1:,:-1,:-1,2] - 0.5*dx[0]**2*dx[1]**2*m[1:,:-1,1:,2] + 0.25*dx[0]**2*dx[1]**2*m[1:,1:,:-1,2] - 0.25*dx[0]**2*dx[1]**2*m[1:,1:,1:,2] + 1.0*dx[0]**2*dx[2]**2*m[:-1,:-1,:-1,2] + 0.5*dx[0]**2*dx[2]**2*m[:-1,:-1,1:,2] - 1.0*dx[0]**2*dx[2]**2*m[:-1,1:,:-1,2] - 0.5*dx[0]**2*dx[2]**2*m[:-1,1:,1:,2] + 0.5*dx[0]**2*dx[2]**2*m[1:,:-1,:-1,2] + 0.25*dx[0]**2*dx[2]**2*m[1:,:-1,1:,2] - 0.5*dx[0]**2*dx[2]**2*m[1:,1:,:-1,2] - 0.25*dx[0]**2*dx[2]**2*m[1:,1:,1:,2] + 1.0*dx[1]**2*dx[2]**2*m[:-1,:-1,:-1,2] + 0.5*dx[1]**2*dx[2]**2*m[:-1,:-1,1:,2] + 0.5*dx[1]**2*dx[2]**2*m[:-1,1:,:-1,2] + 0.25*dx[1]**2*dx[2]**2*m[:-1,1:,1:,2] - 1.0*dx[1]**2*dx[2]**2*m[1:,:-1,:-1,2] - 0.5*dx[1]**2*dx[2]**2*m[1:,:-1,1:,2] - 0.5*dx[1]**2*dx[2]**2*m[1:,1:,:-1,2] - 0.25*dx[1]**2*dx[2]**2*m[1:,1:,1:,2])/(dx[0]*dx[1]*dx[2])
    h[:-1,:-1,1:,0] += -0.222222222222222*A[:,:,:]*(1.0*dx[0]**2*dx[1]**2*m[:-1,:-1,:-1,0] - 1.0*dx[0]**2*dx[1]**2*m[:-1,:-1,1:,0] + 0.5*dx[0]**2*dx[1]**2*m[:-1,1:,:-1,0] - 0.5*dx[0]**2*dx[1]**2*m[:-1,1:,1:,0] + 0.5*dx[0]**2*dx[1]**2*m[1:,:-1,:-1,0] - 0.5*dx[0]**2*dx[1]**2*m[1:,:-1,1:,0] + 0.25*dx[0]**2*dx[1]**2*m[1:,1:,:-1,0] - 0.25*dx[0]**2*dx[1]**2*m[1:,1:,1:,0] - 0.5*dx[0]**2*dx[2]**2*m[:-1,:-1,:-1,0] - 1.0*dx[0]**2*dx[2]**2*m[:-1,:-1,1:,0] + 0.5*dx[0]**2*dx[2]**2*m[:-1,1:,:-1,0] + 1.0*dx[0]**2*dx[2]**2*m[:-1,1:,1:,0] - 0.25*dx[0]**2*dx[2]**2*m[1:,:-1,:-1,0] - 0.5*dx[0]**2*dx[2]**2*m[1:,:-1,1:,0] + 0.25*dx[0]**2*dx[2]**2*m[1:,1:,:-1,0] + 0.5*dx[0]**2*dx[2]**2*m[1:,1:,1:,0] - 0.5*dx[1]**2*dx[2]**2*m[:-1,:-1,:-1,0] - 1.0*dx[1]**2*dx[2]**2*m[:-1,:-1,1:,0] - 0.25*dx[1]**2*dx[2]**2*m[:-1,1:,:-1,0] - 0.5*dx[1]**2*dx[2]**2*m[:-1,1:,1:,0] + 0.5*dx[1]**2*dx[2]**2*m[1:,:-1,:-1,0] + 1.0*dx[1]**2*dx[2]**2*m[1:,:-1,1:,0] + 0.25*dx[1]**2*dx[2]**2*m[1:,1:,:-1,0] + 0.5*dx[1]**2*dx[2]**2*m[1:,1:,1:,0])/(dx[0]*dx[1]*dx[2])
    h[:-1,:-1,1:,1] += -0.222222222222222*A[:,:,:]*(1.0*dx[0]**2*dx[1]**2*m[:-1,:-1,:-1,1] - 1.0*dx[0]**2*dx[1]**2*m[:-1,:-1,1:,1] + 0.5*dx[0]**2*dx[1]**2*m[:-1,1:,:-1,1] - 0.5*dx[0]**2*dx[1]**2*m[:-1,1:,1:,1] + 0.5*dx[0]**2*dx[1]**2*m[1:,:-1,:-1,1] - 0.5*dx[0]**2*dx[1]**2*m[1:,:-1,1:,1] + 0.25*dx[0]**2*dx[1]**2*m[1:,1:,:-1,1] - 0.25*dx[0]**2*dx[1]**2*m[1:,1:,1:,1] - 0.5*dx[0]**2*dx[2]**2*m[:-1,:-1,:-1,1] - 1.0*dx[0]**2*dx[2]**2*m[:-1,:-1,1:,1] + 0.5*dx[0]**2*dx[2]**2*m[:-1,1:,:-1,1] + 1.0*dx[0]**2*dx[2]**2*m[:-1,1:,1:,1] - 0.25*dx[0]**2*dx[2]**2*m[1:,:-1,:-1,1] - 0.5*dx[0]**2*dx[2]**2*m[1:,:-1,1:,1] + 0.25*dx[0]**2*dx[2]**2*m[1:,1:,:-1,1] + 0.5*dx[0]**2*dx[2]**2*m[1:,1:,1:,1] - 0.5*dx[1]**2*dx[2]**2*m[:-1,:-1,:-1,1] - 1.0*dx[1]**2*dx[2]**2*m[:-1,:-1,1:,1] - 0.25*dx[1]**2*dx[2]**2*m[:-1,1:,:-1,1] - 0.5*dx[1]**2*dx[2]**2*m[:-1,1:,1:,1] + 0.5*dx[1]**2*dx[2]**2*m[1:,:-1,:-1,1] + 1.0*dx[1]**2*dx[2]**2*m[1:,:-1,1:,1] + 0.25*dx[1]**2*dx[2]**2*m[1:,1:,:-1,1] + 0.5*dx[1]**2*dx[2]**2*m[1:,1:,1:,1])/(dx[0]*dx[1]*dx[2])
    h[:-1,:-1,1:,2] += -0.222222222222222*A[:,:,:]*(1.0*dx[0]**2*dx[1]**2*m[:-1,:-1,:-1,2] - 1.0*dx[0]**2*dx[1]**2*m[:-1,:-1,1:,2] + 0.5*dx[0]**2*dx[1]**2*m[:-1,1:,:-1,2] - 0.5*dx[0]**2*dx[1]**2*m[:-1,1:,1:,2] + 0.5*dx[0]**2*dx[1]**2*m[1:,:-1,:-1,2] - 0.5*dx[0]**2*dx[1]**2*m[1:,:-1,1:,2] + 0.25*dx[0]**2*dx[1]**2*m[1:,1:,:-1,2] - 0.25*dx[0]**2*dx[1]**2*m[1:,1:,1:,2] - 0.5*dx[0]**2*dx[2]**2*m[:-1,:-1,:-1,2] - 1.0*dx[0]**2*dx[2]**2*m[:-1,:-1,1:,2] + 0.5*dx[0]**2*dx[2]**2*m[:-1,1:,:-1,2] + 1.0*dx[0]**2*dx[2]**2*m[:-1,1:,1:,2] - 0.25*dx[0]**2*dx[2]**2*m[1:,:-1,:-1,2] - 0.5*dx[0]**2*dx[2]**2*m[1:,:-1,1:,2] + 0.25*dx[0]**2*dx[2]**2*m[1:,1:,:-1,2] + 0.5*dx[0]**2*dx[2]**2*m[1:,1:,1:,2] - 0.5*dx[1]**2*dx[2]**2*m[:-1,:-1,:-1,2] - 1.0*dx[1]**2*dx[2]**2*m[:-1,:-1,1:,2] - 0.25*dx[1]**2*dx[2]**2*m[:-1,1:,:-1,2] - 0.5*dx[1]**2*dx[2]**2*m[:-1,1:,1:,2] + 0.5*dx[1]**2*dx[2]**2*m[1:,:-1,:-1,2] + 1.0*dx[1]**2*dx[2]**2*m[1:,:-1,1:,2] + 0.25*dx[1]**2*dx[2]**2*m[1:,1:,:-1,2] + 0.5*dx[1]**2*dx[2]**2*m[1:,1:,1:,2])/(dx[0]*dx[1]*dx[2])
    h[:-1,1:,:-1,0] += 0.222222222222222*A[:,:,:]*(0.5*dx[0]**2*dx[1]**2*m[:-1,:-1,:-1,0] - 0.5*dx[0]**2*dx[1]**2*m[:-1,:-1,1:,0] + 1.0*dx[0]**2*dx[1]**2*m[:-1,1:,:-1,0] - 1.0*dx[0]**2*dx[1]**2*m[:-1,1:,1:,0] + 0.25*dx[0]**2*dx[1]**2*m[1:,:-1,:-1,0] - 0.25*dx[0]**2*dx[1]**2*m[1:,:-1,1:,0] + 0.5*dx[0]**2*dx[1]**2*m[1:,1:,:-1,0] - 0.5*dx[0]**2*dx[1]**2*m[1:,1:,1:,0] - 1.0*dx[0]**2*dx[2]**2*m[:-1,:-1,:-1,0] - 0.5*dx[0]**2*dx[2]**2*m[:-1,:-1,1:,0] + 1.0*dx[0]**2*dx[2]**2*m[:-1,1:,:-1,0] + 0.5*dx[0]**2*dx[2]**2*m[:-1,1:,1:,0] - 0.5*dx[0]**2*dx[2]**2*m[1:,:-1,:-1,0] - 0.25*dx[0]**2*dx[2]**2*m[1:,:-1,1:,0] + 0.5*dx[0]**2*dx[2]**2*m[1:,1:,:-1,0] + 0.25*dx[0]**2*dx[2]**2*m[1:,1:,1:,0] + 0.5*dx[1]**2*dx[2]**2*m[:-1,:-1,:-1,0] + 0.25*dx[1]**2*dx[2]**2*m[:-1,:-1,1:,0] + 1.0*dx[1]**2*dx[2]**2*m[:-1,1:,:-1,0] + 0.5*dx[1]**2*dx[2]**2*m[:-1,1:,1:,0] - 0.5*dx[1]**2*dx[2]**2*m[1:,:-1,:-1,0] - 0.25*dx[1]**2*dx[2]**2*m[1:,:-1,1:,0] - 1.0*dx[1]**2*dx[2]**2*m[1:,1:,:-1,0] - 0.5*dx[1]**2*dx[2]**2*m[1:,1:,1:,0])/(dx[0]*dx[1]*dx[2])
